+            CassMsg::ModelDownloadProgress {
+                bytes_downloaded,
+                total,
+            } => {
+                let progress_pct = if total == 0 {
+                    0
+                } else {
+                    ((bytes_downloaded.saturating_mul(100) / total).min(100)) as u8
+                };
+                self.semantic_availability = SemanticAvailability::Downloading {
