+                    let done_mb = bytes_downloaded as f64 / 1_048_576.0;
+                    let total_mb = total as f64 / 1_048_576.0;
+                    self.status = format!(
+                        "Downloading semantic model: {progress_pct}% ({done_mb:.1}/{total_mb:.1} MB)"
